noncompliant:
// Noncompliant: Invalid #include syntax
#include stdio.h      // Missing angle brackets or quotes
#include <stdio.h extra> // Extra text after filename
#include              // Missing filename entirely

compliant:
// Compliant: Proper #include syntax
#include <stdio.h>    // System header with angle brackets
#include "myheader.h" // User header with quotes
#include <stdlib.h>   // Another system header
